"""High-fidelity pixel-vector icon catalog (24x24)."""

# Common palette
P_OUTLINE = "currentColor"  # Allow tinting via CSS/style
P_FILL = "currentColor"
P_ACCENT = "#ffffff"  # Internal detail

# We use simple paths. If tinting is needed, the renderer applies 'color' style.
# We use opacity for shading/duotone effects where possible.

def _path(d: str, opacity: float = 1.0) -> str:
    op = f' opacity="{opacity}"' if opacity < 1.0 else ""
    return f'<path d="{d}" fill="currentColor"{op}/>'


def _scaled_paths(paths: tuple[str, ...], scale: float) -> str:
    return "".join(f'<path d="{d}" fill="currentColor" transform="scale({scale})"/>' for d in paths)


